-- ============================================================
-- EAC REGISTRAR SYSTEM — FULL SCHOOL PC SETUP
-- Single file: creates DB, schema, seed data, and demo accounts
-- ============================================================
-- INSTRUCTIONS:
--   1. Open MySQL Workbench
--   2. File → Open SQL Script → select this file
--   3. Click the lightning bolt (Execute All)
--   4. Start the Spring Boot app → login: admin / 1234
-- ============================================================

-- Step 0: Create and select the database
DROP DATABASE IF EXISTS registrar_db_v2;
CREATE DATABASE registrar_db_v2
    CHARACTER SET utf8mb4
    COLLATE utf8mb4_unicode_ci;

USE registrar_db_v2;

-- ============================================================
-- SECTION 1: CORE SYSTEM TABLES
-- ============================================================

CREATE TABLE system_settings (
    setting_key   VARCHAR(50) PRIMARY KEY,
    setting_value VARCHAR(100)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

INSERT INTO system_settings VALUES
    ('PRELIM_START',      '2025-01-01'),
    ('PRELIM_END',        '2026-12-31'),
    ('MIDTERM_START',     '2025-01-01'),
    ('MIDTERM_END',       '2026-12-31'),
    ('FINAL_START',       '2025-01-01'),
    ('FINAL_END',         '2026-12-31'),
    ('PRELIM_OVERRIDE',   'FORCE_OPEN'),
    ('MIDTERM_OVERRIDE',  'FORCE_OPEN'),
    ('FINAL_OVERRIDE',    'FORCE_OPEN');

CREATE TABLE audit_logs (
    log_id   INT AUTO_INCREMENT PRIMARY KEY,
    admin_id INT,
    action   VARCHAR(255),
    log_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ============================================================
-- SECTION 2: MASTER USER TABLE
-- ============================================================

CREATE TABLE sys_users (
    user_id             INT AUTO_INCREMENT PRIMARY KEY,
    username            VARCHAR(50) UNIQUE,
    password            VARCHAR(255),
    real_name           VARCHAR(100),
    role                VARCHAR(30),
    program_code        VARCHAR(20),
    year_level          INT DEFAULT 1,
    semester            INT DEFAULT 1,
    term_year           VARCHAR(30) DEFAULT 'SL_1120252026',
    is_active           TINYINT(1) DEFAULT 1,
    status              VARCHAR(30) DEFAULT 'ACTIVE',
    granted_permissions TEXT,
    admission_status    VARCHAR(50),
    admission_date      DATETIME,
    email               VARCHAR(150),
    contact_number      VARCHAR(30),
    scholarship_type    VARCHAR(20)   NOT NULL DEFAULT 'NONE',
    discount_percentage DECIMAL(5,2) NOT NULL DEFAULT 0.00,
    enrollment_blocked  TINYINT(1)  NOT NULL DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ============================================================
-- SECTION 3: LEGACY GRADING TABLES
-- ============================================================

CREATE TABLE curriculum_catalog (
    course_code VARCHAR(20) PRIMARY KEY,
    description VARCHAR(150),
    units       INT DEFAULT 3,
    has_lab     TINYINT(1) DEFAULT 0,
    curriculum_year VARCHAR(20) DEFAULT '2024-2025'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE class_schedules (
    schedule_id  INT AUTO_INCREMENT PRIMARY KEY,
    course_code  VARCHAR(20),
    section      VARCHAR(20),
    faculty_id   INT,
    day          VARCHAR(20),
    start_time   INT DEFAULT 0,
    end_time     INT DEFAULT 0,
    room         VARCHAR(30),
    status       VARCHAR(50) DEFAULT 'OPEN',
    is_unlocked  TINYINT(1) DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE student_grades (
    grade_id       INT AUTO_INCREMENT PRIMARY KEY,
    schedule_id    INT,
    student_name   VARCHAR(100),
    student_id     INT,
    prelim         DECIMAL(5,2) DEFAULT 0,
    midterm        DECIMAL(5,2) DEFAULT 0,
    `final`        DECIMAL(5,2) DEFAULT 0,
    semestral_grade DECIMAL(5,2) DEFAULT 0,
    remarks        VARCHAR(30) DEFAULT 'Ongoing',
    lab_remarks    VARCHAR(30) DEFAULT 'Ongoing',
    previous_grade VARCHAR(20),
    status         VARCHAR(50) DEFAULT 'DRAFT'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE vpaa_extensions (
    ext_id      INT AUTO_INCREMENT PRIMARY KEY,
    schedule_id INT,
    faculty_id  INT,
    status      VARCHAR(50) DEFAULT 'PENDING',
    reason      VARCHAR(255)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE grade_change_requests (
    request_id      INT AUTO_INCREMENT PRIMARY KEY,
    grade_id        INT,
    student_name    VARCHAR(100),
    course_code     VARCHAR(20),
    faculty_name    VARCHAR(100),
    requested_grade VARCHAR(20),
    reason          TEXT,
    status          VARCHAR(30) DEFAULT 'PENDING',
    request_date    TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ============================================================
-- SECTION 4: FINANCE & ADMISSIONS TABLES
-- ============================================================

CREATE TABLE student_ledger (
    ledger_id        INT AUTO_INCREMENT PRIMARY KEY,
    student_id       INT,
    transaction_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    transaction_type VARCHAR(30),
    description      VARCHAR(255),
    debit            DECIMAL(10,2) DEFAULT 0.00,
    credit           DECIMAL(10,2) DEFAULT 0.00
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE applicant_payments (
    payment_id     INT AUTO_INCREMENT PRIMARY KEY,
    applicant_id   VARCHAR(50) NOT NULL,
    payment_amount DECIMAL(10,2) NOT NULL,
    payment_date   TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    status         VARCHAR(20) DEFAULT 'UNPROCESSED'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE payments (
    payment_id       BIGINT AUTO_INCREMENT PRIMARY KEY,
    transaction_id   VARCHAR(60)   NOT NULL,
    or_number        VARCHAR(20)   DEFAULT NULL,
    reference_number VARCHAR(50)   NOT NULL,
    amount           DECIMAL(12,2) NOT NULL DEFAULT 0.00,
    payment_method   VARCHAR(60)   DEFAULT 'Cash (OTC)',
    semester         INT           DEFAULT 1,
    year_level       INT           DEFAULT 1,
    term_year        VARCHAR(30)   DEFAULT NULL,
    remarks          VARCHAR(150)  DEFAULT NULL,
    payment_date     DATETIME      NOT NULL DEFAULT CURRENT_TIMESTAMP,
    status           VARCHAR(20)   NOT NULL DEFAULT 'COMPLETED',
    UNIQUE KEY uk_transaction (transaction_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ============================================================
-- SECTION 5: EAC APPLICANT PORTAL TABLES
-- ============================================================

CREATE TABLE eac_applicants (
    ref_no                         VARCHAR(30) PRIMARY KEY,
    applicant_status               VARCHAR(50)  DEFAULT 'SUBMITTED',
    term_year                      VARCHAR(30),
    first_name                     VARCHAR(100),
    last_name                      VARCHAR(100),
    middle_name                    VARCHAR(100),
    middle_initial                 VARCHAR(10),
    middle_name_na                 TINYINT(1)   DEFAULT 0,
    extension                      VARCHAR(20),
    sex                            VARCHAR(10),
    dob                            VARCHAR(20),
    place_of_birth                 TEXT,
    civil_status                   VARCHAR(30),
    religion                       VARCHAR(60),
    nationality                    VARCHAR(60),
    citizenship                    VARCHAR(60),
    age                            INT,
    four_ps                        TINYINT(1)   DEFAULT 0,
    indigenous                     TINYINT(1)   DEFAULT 0,
    international_student          TINYINT(1)   DEFAULT 0,
    email                          VARCHAR(150),
    email_verified                 TINYINT(1)   DEFAULT 0,
    mobile                         VARCHAR(30),
    landline                       VARCHAR(30),
    street                         TEXT,
    city                           VARCHAR(100),
    province                       VARCHAR(100),
    zip                            VARCHAR(10),
    emergency_contact_name         VARCHAR(150),
    emergency_contact_mobile       VARCHAR(30),
    emergency_contact_relationship VARCHAR(60),
    father_name                    VARCHAR(150),
    father_occupation              VARCHAR(100),
    father_contact                 VARCHAR(30),
    father_address                 TEXT,
    mother_name                    VARCHAR(150),
    mother_occupation              VARCHAR(100),
    mother_contact                 VARCHAR(30),
    mother_address                 TEXT,
    guardian_name                  VARCHAR(150),
    guardian_contact               VARCHAR(30),
    guardian_relationship          VARCHAR(60),
    sibling_count                  INT,
    sibling_order                  VARCHAR(30),
    monthly_income                 VARCHAR(30),
    academic_level                 VARCHAR(30),
    elementary_school              TEXT,
    elementary_address             TEXT,
    elementary_year                VARCHAR(20),
    jhs_school                     TEXT,
    jhs_address                    TEXT,
    jhs_year                       VARCHAR(20),
    shs_school                     TEXT,
    shs_address                    TEXT,
    shs_track                      VARCHAR(60),
    shs_year                       VARCHAR(20),
    last_school                    TEXT,
    last_school_year               VARCHAR(20),
    course_taken                   VARCHAR(100),
    program1                       VARCHAR(20),
    program2                       VARCHAR(20),
    form138_path                   VARCHAR(255),
    form138_verified               TINYINT(1)   DEFAULT 0,
    good_moral_path                VARCHAR(255),
    good_moral_verified            TINYINT(1)   DEFAULT 0,
    psa_birth_cert_path            VARCHAR(255),
    psa_birth_cert_verified        TINYINT(1)   DEFAULT 0,
    id_picture_path                VARCHAR(255),
    id_picture_verified            TINYINT(1)   DEFAULT 0,
    marriage_cert_path             VARCHAR(255),
    marriage_cert_verified         TINYINT(1)   DEFAULT 0,
    other_doc_path                 VARCHAR(255),
    other_doc_verified             TINYINT(1)   DEFAULT 0,
    interview_date                 TEXT,
    interview_time                 TEXT,
    interview_link                 TEXT,
    remarks                        TEXT,
    revised                        TINYINT(1)   DEFAULT 0,
    reopen_until                   DATETIME,
    created_at                     DATETIME     DEFAULT CURRENT_TIMESTAMP,
    updated_at                     DATETIME     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE eac_application_logs (
    log_id        INT AUTO_INCREMENT PRIMARY KEY,
    ref_no        VARCHAR(30),
    action        VARCHAR(100),
    performed_by  VARCHAR(60),
    remarks       TEXT,
    log_timestamp DATETIME
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ============================================================
-- SECTION 6: JAYPEE ENGINE TABLES (jp_)
-- ============================================================

CREATE TABLE jp_programs (
    program_code VARCHAR(20) PRIMARY KEY,
    program_name VARCHAR(150),
    school_name  VARCHAR(100),
    category     VARCHAR(60)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE jp_students (
    id             BIGINT AUTO_INCREMENT PRIMARY KEY,
    student_number VARCHAR(50) UNIQUE,
    first_name     VARCHAR(50),
    last_name      VARCHAR(50),
    email          VARCHAR(100),
    program_code   VARCHAR(20),
    current_year   INT DEFAULT 1,
    status         VARCHAR(30) DEFAULT 'ADMITTED'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE jp_courses (
    course_id              INT AUTO_INCREMENT PRIMARY KEY,
    course_code            VARCHAR(20),
    course_title           VARCHAR(100),
    units                  INT,
    program_code           VARCHAR(20),
    prerequisite_course_id INT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE jp_class_sections (
    section_id   INT AUTO_INCREMENT PRIMARY KEY,
    course_id    INT,
    section_name VARCHAR(20),
    max_capacity INT DEFAULT 40
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE jp_class_schedules (
    schedule_id INT AUTO_INCREMENT PRIMARY KEY,
    section_id  INT,
    course_id   INT,
    day_of_week VARCHAR(20),
    start_time  TIME,
    end_time    TIME,
    room        VARCHAR(30),
    faculty_id  INT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE jp_student_enlistments (
    enlistment_id INT AUTO_INCREMENT PRIMARY KEY,
    student_id    BIGINT,
    course_id     INT,
    section_id    INT,
    status        VARCHAR(20) DEFAULT 'ENROLLED',
    enlisted_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE jp_subject_logs (
    log_id     INT AUTO_INCREMENT PRIMARY KEY,
    student_id BIGINT,
    course_id  INT,
    action     VARCHAR(20),
    log_date   TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE jp_grades (
    grade_id   INT AUTO_INCREMENT PRIMARY KEY,
    student_id BIGINT,
    course_id  INT,
    status     VARCHAR(20)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE jp_curriculum_mapping (
    mapping_id   INT AUTO_INCREMENT PRIMARY KEY,
    program_code VARCHAR(20),
    course_id    INT,
    year_level   INT,
    semester     INT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

